**Notification Hook**

```typescript
// @/src/hooks/useNotification.hook.ts
import { createContext, useContext, useState, useEffect } from 'react';
import { NotificationProps } from '../helpers/notification.helpers';

const NotificationContext = createContext(null);

const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (notificationElem) {
      const notification = async (props: NotificationProps) => {
        try {
          await notify(notificationElem, props);
        } catch (error) {
          setError(error);
        }
      };
      return notification;
    }
  }, [notificationElem]);

  const notify = (props: NotificationProps) => {
    setError(null);
    return notification(props);
  };

  return { notify, error };
};

export default useNotification;
